with open('task/4/ConstantFolding.cpp', 'w') as f:
    f.write('''#include "ConstantFolding.hpp"

using namespace llvm;

PreservedAnalyses
ConstantFolding::run(Module& mod, ModuleAnalysisManager& mam)
{
  int constFoldTimes = 0;

  for (auto& func : mod) {
    for (auto& bb : func) {
      std::vector<Instruction*> instToErase;
      for (auto& inst : bb) {
        if (auto binOp = dyn_cast<BinaryOperator>(&inst)) {
          Value* lhs = binOp->getOperand(0);
          Value* rhs = binOp->getOperand(1);
          auto constLhs = dyn_cast<ConstantInt>(lhs);
          auto constRhs = dyn_cast<ConstantInt>(rhs);
          switch (binOp->getOpcode()) {
            case Instruction::Add:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::getSigned(binOp->getType(), constLhs->getSExtValue() + constRhs->getSExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::Sub:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::getSigned(binOp->getType(), constLhs->getSExtValue() - constRhs->getSExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::Mul:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::getSigned(binOp->getType(), constLhs->getSExtValue() * constRhs->getSExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::UDiv:
              if (constLhs && constRhs && constRhs->getZExtValue() != 0) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getZExtValue() / constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::SDiv:
              if (constLhs && constRhs && constRhs->getSExtValue() != 0) {
                binOp->replaceAllUsesWith(ConstantInt::getSigned(binOp->getType(), constLhs->getSExtValue() / constRhs->getSExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::Shl:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getZExtValue() << constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::LShr:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getZExtValue() >> constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::AShr:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getSExtValue() >> constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::And:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getZExtValue() & constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::Or:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getZExtValue() | constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::Xor:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getZExtValue() ^ constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            default: break;
          }
        }
      }
      for (auto& i : instToErase)
        i->eraseFromParent();
    }
  }

  mOut << "ConstantFolding running...\\nTo eliminate " << constFoldTimes
       << " instructions\\n";
  return PreservedAnalyses::all();
}
''')
print('Restored and extended')
